(async function a(){try{let A=await fetch('programma.json'),b=await A.json(),d=document.querySelector('.diretta-subtitle');document.title=`Diretta · ${b.titolo} · ${b.luogo}`;let c=document.querySelector('.diretta-title');c&&(c.textContent=b.titolo);d&&(d.textContent=`${b.titolo} — ${b.sottotitolo}`||'');let e=document.getElementById('diretta-ref');e&&(e.innerHTML=await fetch('diretta.ref').then(r=>r.text()))}catch(e){}})();
